const { execSync } = require('child_process');
const fs = require('fs');

const runCommand = (command, silent = false) => {
  try {
    if (silent) {
      return execSync(command, { encoding: 'utf8' });
    }
    execSync(command, { stdio: 'inherit' });
    return true;
  } catch (error) {
    console.error(`Command failed: ${command}`);
    process.exit(1);
  }
};

const generateSBOM = () => {
  try {
    const sbomFile = 'sbom.json';
    runCommand('npm install -g @cyclonedx/cyclonedx-npm');
    runCommand(`cyclonedx-npm --output ${sbomFile} --format json`);
    
    if (fs.existsSync(sbomFile)) {
      console.log('SBOM generated successfully');
      return sbomFile;
    }
  } catch (error) {
    console.error('Failed to generate SBOM:', error);
    process.exit(1);
  }
  return null;
};

const main = () => {
  console.log('Starting CI/CD pipeline...');
  
  runCommand('npm ci --prefer-offline --no-audit');
  runCommand('npm test');
  runCommand('npm run build');
  
  const sbomFile = generateSBOM();
  
  if (sbomFile) {
    console.log('Deploying with SBOM:', sbomFile);
    runCommand('npm run deploy');
  } else {
    console.log('Deploying without SBOM');
    runCommand('npm run deploy');
  }
  
  console.log('Pipeline completed successfully');
};

main();